```plantuml
@startuml
skinparam classAttributeIconSize 0

interface Monster {
    + announce()
    + move()
}

interface Bokoblin {
    + bludgeon()
    + defend()
}

interface Moblin {
    + stab()
    + kick()
}

class BlueBokoblin {
    + announce()
    + move()
    + bludgeon()
    + defend()
}

class NormalBokoblin {
    + announce()
    + move()
    + bludgeon()
    + defend()
}

class BlueMoblin {
    + announce()
    + move()
    + stab()
    + kick()
}

class NormalMoblin {
    + announce()
    + move()
    + stab()
    + kick()
}

interface Dungeon {
    + newBokoblin(): Bokoblin
    + newMoblin(): Moblin
}

class MediumDungeon {
    + newBokoblin(): Bokoblin
    + newMoblin(): Moblin
}

class EasyDungeon {
    + newBokoblin(): Bokoblin
    + newMoblin(): Moblin
}

class Encounter {
    - enemies: [Monster]
    - dungeon: Dungeon
    + announceEnemies()
    + moveEnemies()
}

' Inheritance relationships
Monster <|-- Bokoblin
Monster <|-- Moblin
Bokoblin <|-- BlueBokoblin
Bokoblin <|-- NormalBokoblin
Moblin <|-- BlueMoblin
Moblin <|-- NormalMoblin
Dungeon <|-- MediumDungeon
Dungeon <|-- EasyDungeon

' Dependency relationships (dashed arrows)
MediumDungeon ..> BlueBokoblin : creates
MediumDungeon ..> BlueMoblin : creates
EasyDungeon ..> NormalBokoblin : creates
EasyDungeon ..> NormalMoblin : creates
Encounter o-- Dungeon : uses
Encounter --> Monster : manages

@enduml
